//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: Style application order (docDefaults -> table -> numbering -> para ->
//! char -> direct).
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from ISO/IEC
//! 29500-1, the normative XSD, and the [MS-OI29500] implementer notes. A FAILING
//! assertion here is NOT a flaky test: it encodes a real divergence between
//! stemma and Microsoft Word's documented behaviour and must be triaged as a
//! Word-compliance gap (fix the engine or the model), never "made green" by
//! weakening the assertion.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So these tests assert on the READ side (read_accepted /
//! read_rejected text) and on opens-clean validity — never on re-serialized XML
//! of an unedited document, which would only re-confirm verbatim preservation.

use stemma::api::{Document, validate};

// ─── Prelude: minimal valid .docx plumbing ──────────────────────────────────

/// Content-type override for a known extra part. Mirrors the overrides Word
/// writes for styles.xml / numbering.xml.
fn content_type_override(part: &str) -> Option<&'static str> {
    match part {
        "word/styles.xml" => Some(
            r#"<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>"#,
        ),
        "word/numbering.xml" => Some(
            r#"<Override PartName="/word/numbering.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/>"#,
        ),
        _ => None,
    }
}

/// Document-rels relationship entry for a known extra part.
fn doc_rel(part: &str, rid: &str) -> Option<String> {
    match part {
        "word/styles.xml" => Some(format!(
            r#"<Relationship Id="{rid}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>"#
        )),
        "word/numbering.xml" => Some(format!(
            r#"<Relationship Id="{rid}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering" Target="numbering.xml"/>"#
        )),
        _ => None,
    }
}

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. Each `(part, xml)` in
/// `extra_parts` is added as its own zip entry, with a matching
/// `[Content_Types].xml` override and `word/_rels/document.xml.rels` entry.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    let mut overrides = String::new();
    for (part, _) in extra_parts {
        let ov = content_type_override(part)
            .unwrap_or_else(|| panic!("no content-type override known for extra part {part}"));
        overrides.push_str(ov);
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    let mut doc_rels_inner = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let rid = format!("rIdX{}", i + 1);
        let r = doc_rel(part, &rid)
            .unwrap_or_else(|| panic!("no document rel known for extra part {part}"));
        doc_rels_inner.push_str(&r);
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_inner}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("document.xml present");
    let mut s = String::new();
    use std::io::Read;
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse -> serialize(default) -> the resulting `word/document.xml` String.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// True when `validate()` reports no errors (Word opens without repair).
fn opens_clean(bytes: &[u8]) -> bool {
    validate(bytes).ok
}

/// Render the validation issues for an assertion message.
fn validation_detail(bytes: &[u8]) -> String {
    let report = validate(bytes);
    if report.issues.is_empty() {
        "<no issues>".to_string()
    } else {
        report
            .issues
            .iter()
            .map(|i| {
                format!(
                    "[{:?}] {}{}",
                    i.code,
                    i.message,
                    i.context
                        .as_deref()
                        .map(|c| format!(" ({c})"))
                        .unwrap_or_default()
                )
            })
            .collect::<Vec<_>>()
            .join("; ")
    }
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for accept")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for reject")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

