#[test]
fn docdefaults_pprdefault_only_no_rprdefault_opens_clean() {
    let body = r#"<w:p><w:r><w:t>Centered default only</w:t></w:r></w:p><w:sectPr/>"#;
    let styles = (
        "word/styles.xml",
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:pPrDefault><w:pPr><w:jc w:val="center"/></w:pPr></w:pPrDefault></w:docDefaults></w:styles>"#,
    );
    let b = make_docx(body, &[styles]);
    assert!(
        opens_clean(&b),
        "ISO 29500-1 §17.7.5.1/§17.7.5.3, ECMA-376 §A.1 CT_DocDefaults: rPrDefault is minOccurs=0, so a docDefaults carrying only pPrDefault is schema-valid and must open without repair. validate() issues: {}",
        validation_detail(&b)
    );
}

