#[test]
fn toggle_xor_table_level_with_para_chain_cancels_bold() {
    // Render-side XOR resolution is an oracle (Word) question; the daily check
    // here is opens-clean validity of the schema-valid worked example.
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="TblBold"/></w:tblPr><w:tr><w:tc><w:p><w:pPr><w:pStyle w:val="ParaBold"/></w:pPr><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let styles = (
        "word/styles.xml",
        "<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n<w:styles xmlns:w=\"http://schemas.openxmlformats.org/wordprocessingml/2006/main\"><w:style w:type=\"table\" w:styleId=\"TblBold\"><w:name w:val=\"TblBold\"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type=\"paragraph\" w:styleId=\"ParaBold\"><w:name w:val=\"ParaBold\"/><w:rPr><w:b/></w:rPr></w:style></w:styles>",
    );
    let b = make_docx(body, &[styles]);
    assert!(
        opens_clean(&b),
        "ISO 29500-1 §17.7.3 worked example: a table whose table style and a contained paragraph's style both set the bold toggle is schema-valid; Word opens it without repair (the table-true XOR para-true = off resolution is a render concern). validate() issues: {}",
        validation_detail(&b)
    );
}

